import React, {Component} from 'react'
import {connect} from 'react-redux'
import {increment, decrement, counterReset} from '../../actions'
import i18n from "../i18n"

class Counter extends Component {
    render() {
        console.log('render counter')
        const { t } = this.props
        return (
            <div className="h5 mt-3">
                <div className="m-2">{this.props.count}</div>
                <button
                    className="btn btn-success m-2"
                    onClick={this.handleIncrement}
                >
                    {t('increment')}
                </button>
                <button
                    className="btn btn-danger m-2"
                    onClick={this.handleDecrement}
                >
                    {t('decrement')}
                </button>
                <button
                    className="btn btn-primary m-2"
                    onClick={this.handleReset}
                >
                    {t('Reset')}
                </button>
            </div>
        )
    }

    handleIncrement = () => {
        this.props.dispatchIncrement()
    }

    handleDecrement = () => {
        this.props.dispatchDecrement()
    }

    handleReset = () => {
        this.props.dispatchReset()
    }
}

const mapStateToProps = (state) => ({
    count: state.count
})

const mapDispatchToProps = {
    dispatchIncrement: increment,
    dispatchDecrement: decrement,
    dispatchReset: counterReset
}

/*const mapDispatchToProps = (dispatch) => ({
    dispatchIncrement: () => dispatch(increment())
})*/

export default connect(mapStateToProps, mapDispatchToProps)(i18n(Counter))
